// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_openalex === false) return [{ json: { _source: 'openalex', _empty: true, _disabled_by_user: true } }];
// DATES_PER_BASE_v1
// DIRECT_ARTICLES_BYPASS_v1 - si direct_articles fournis, on retourne vide (PubMed s'en charge)
const __DIRECT_CHECK = $input.all()[0] && $input.all()[0].json;
if (__DIRECT_CHECK && Array.isArray(__DIRECT_CHECK.direct_articles) && __DIRECT_CHECK.direct_articles.length > 0) {
  return [];
}

// ─── OPENALEX — Fetch via proxy (paginated, heartbeat-safe) ───
const input = $input.all()[0].json;
const query = encodeURIComponent(input.openalex_query || input.search_query || '');
var __dY1 = parseInt(input.date_start) || 0, __dY2 = parseInt(input.date_end) || 0;
var __dsuf = (__dY1 && __dY2) ? ('&filter=from_publication_date:' + __dY1 + '-01-01,to_publication_date:' + __dY2 + '-12-31') : '';
const meta = {
  question: input.question || '',
  criteria: input.criteria || '',
  search_query: input.search_query || '',
  output_folder: input.output_folder || '',
  prefilter_enabled: input.prefilter_enabled,
  prefilter_count: input.prefilter_count,
  max_results: input.max_results,
  pubmed_query: input.pubmed_query || '',
  openalex_query: input.openalex_query || '',
  crossref_query: input.crossref_query || ''
};

const PROXY = 'http://host.docker.internal:3456';
const PER_PAGE = 200;
const MAX_RESULTS = parseInt(input.cap_openalex) || parseInt(input.max_results) || 1000;

let cursor = '*';
let allResults = [];
let pageNum = 0;

try {
  while (cursor && allResults.length < MAX_RESULTS) {
    pageNum++;
    const targetUrl = `https://api.openalex.org/works?search=${query}${__dsuf}&per-page=${PER_PAGE}&cursor=${encodeURIComponent(cursor)}&select=id,doi,title,display_name,abstract_inverted_index,authorships,publication_year,primary_location&mailto=ultralab@review.org`;
    const proxyUrl = PROXY + '?url=' + encodeURIComponent(targetUrl);

    let resp;
    try {
      resp = await this.helpers.httpRequest({ method: 'GET', url: proxyUrl, timeout: 120000 });
    } catch(e) {
      console.log('OpenAlex HTTP error page ' + pageNum + ': ' + e.message);
      break;
    }

    const works = resp.results || [];
    if (works.length === 0) break;

    for (const w of works) {
      const journal = (w.primary_location && w.primary_location.source)
        ? (w.primary_location.source.display_name || '') : '';

      let abstract = '';
      if (w.abstract_inverted_index) {
        const pairs = [];
        for (const [word, positions] of Object.entries(w.abstract_inverted_index)) {
          for (const pos of positions) { pairs.push([pos, word]); }
        }
        pairs.sort((a, b) => a[0] - b[0]);
        abstract = pairs.map(p => p[1]).join(' ');
      }

      const authors = (w.authorships || []).map(a => a.author ? a.author.display_name : '').filter(Boolean);

      allResults.push({
        _source: 'openalex',
        id: w.id || '',
        doi: w.doi || '',
        title: w.display_name || w.title || '',
        abstract: abstract,
        authors: authors,
        year: w.publication_year || '',
        journal: journal,
        ...meta
      });
    }

    cursor = (resp.meta && resp.meta.next_cursor) ? resp.meta.next_cursor : null;
    console.log(`OpenAlex page ${pageNum}: +${works.length} (total: ${allResults.length})`);

    await new Promise(r => setTimeout(r, 150));
  }
} catch(e) {
  console.log('OpenAlex fatal error: ' + e.message);
}

console.log('OpenAlex DONE: ' + allResults.length + ' articles');

if (allResults.length === 0) {
  return [{ json: { _source: 'openalex', _empty: true, ...meta } }];
}
return allResults.slice(0, MAX_RESULTS).map(r => ({ json: r })); // R3_CAP_FETCH_v1

