if ((($input.all()[0] && $input.all()[0].json) || {}).enable_crossref === false) return [{ json: { _source: 'crossref', _empty: true, _disabled_by_user: true } }];
// DATES_PER_BASE_v1
// DIRECT_ARTICLES_BYPASS_v1 - si direct_articles fournis, on retourne vide (PubMed s'en charge)
const __DIRECT_CHECK = $input.all()[0] && $input.all()[0].json;
if (__DIRECT_CHECK && Array.isArray(__DIRECT_CHECK.direct_articles) && __DIRECT_CHECK.direct_articles.length > 0) {
  return [];
}

// ─── CROSSREF — Fetch via proxy (paginated, heartbeat-safe) ───
const input = $input.all()[0].json;
const query = encodeURIComponent(input.crossref_query || input.search_query || '');
var __dY1 = parseInt(input.date_start) || 0, __dY2 = parseInt(input.date_end) || 0;
var __dsuf = (__dY1 && __dY2) ? ('&filter=from-pub-date:' + __dY1 + '-01-01,until-pub-date:' + __dY2 + '-12-31') : '';
const meta = {
  question: input.question || '',
  criteria: input.criteria || '',
  search_query: input.search_query || '',
  output_folder: input.output_folder || '',
  prefilter_enabled: input.prefilter_enabled,
  prefilter_count: input.prefilter_count,
  max_results: input.max_results,
  pubmed_query: input.pubmed_query || '',
  openalex_query: input.openalex_query || '',
  crossref_query: input.crossref_query || ''
};

const PROXY = 'http://host.docker.internal:3456';
const ROWS = 200;
const MAX_RESULTS = parseInt(input.cap_crossref) || parseInt(input.max_results) || 1000;

let cursor = '*';
let allResults = [];
let pageNum = 0;

try {
  while (cursor && allResults.length < MAX_RESULTS) {
    pageNum++;
    const targetUrl = `https://api.crossref.org/works?query=${query}${__dsuf}&rows=${ROWS}&cursor=${encodeURIComponent(cursor)}&select=DOI,title,abstract,author,published,container-title&mailto=ultralab@review.org`;
    const proxyUrl = PROXY + '?url=' + encodeURIComponent(targetUrl);

    let resp;
    try {
      resp = await this.helpers.httpRequest({ method: 'GET', url: proxyUrl, timeout: 120000 });
    } catch(e) {
      console.log('Crossref HTTP error page ' + pageNum + ': ' + e.message);
      break;
    }

    const items = (resp.message && resp.message.items) ? resp.message.items : [];
    if (items.length === 0) break;

    for (const w of items) {
      const authors = (w.author || []).map(a => [a.given, a.family].filter(Boolean).join(' ')).filter(Boolean);
      const title = Array.isArray(w.title) ? w.title[0] || '' : (w.title || '');
      const journal = Array.isArray(w['container-title']) ? w['container-title'][0] || '' : (w['container-title'] || '');
      let year = '';
      if (w.published && w.published['date-parts'] && w.published['date-parts'][0]) {
        year = w.published['date-parts'][0][0] || '';
      }

      allResults.push({
        _source: 'crossref',
        id: w.DOI ? 'doi:' + w.DOI : '',
        doi: w.DOI || '',
        title: title,
        abstract: (w.abstract || '').replace(/<[^>]+>/g, ''),
        authors: authors,
        year: String(year),
        journal: journal,
        ...meta
      });
    }

    cursor = (resp.message && resp.message['next-cursor']) ? resp.message['next-cursor'] : null;
    console.log(`Crossref page ${pageNum}: +${items.length} (total: ${allResults.length})`);

    await new Promise(r => setTimeout(r, 150));
  }
} catch(e) {
  console.log('Crossref fatal error: ' + e.message);
}

console.log('Crossref DONE: ' + allResults.length + ' articles');

if (allResults.length === 0) {
  return [{ json: { _source: 'crossref', _empty: true, ...meta } }];
}
return allResults.slice(0, MAX_RESULTS).map(r => ({ json: r })); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_pubmed === false) return [{ json: { _source: 'pubmed', _empty: true, _disabled_by_user: true } }];
// DIRECT_ARTICLES_BYPASS_v1 - si direct_articles fournis, on les retourne directement
(function() {
  try {
    const _in = $input.all()[0];
    const _data = (_in && _in.json) ? _in.json : {};
    if (Array.isArray(_data.direct_articles) && _data.direct_articles.length > 0) {
      console.log('[PubMed Fetch] BYPASS : ' + _data.direct_articles.length + ' direct_articles fournis');
    }
  } catch (e) {}
})();
const __DIRECT_INPUT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT_INPUT && Array.isArray(__DIRECT_INPUT.direct_articles) && __DIRECT_INPUT.direct_articles.length > 0) {
  return __DIRECT_INPUT.direct_articles.map(function(a) {
    return { json: Object.assign({}, a, { source: a.source || 'direct_input' }) };
  });
}

// ─── PUBMED — efetch via proxy (paginated, heartbeat-safe) ───
const input = $input.all()[0].json;
const query = encodeURIComponent(input.pubmed_query || input.search_query || '');
const meta = {
  question: input.question || '',
  criteria: input.criteria || '',
  search_query: input.search_query || '',
  output_folder: input.output_folder || '',
  prefilter_enabled: input.prefilter_enabled,
  prefilter_count: input.prefilter_count,
  max_results: input.max_results,
  pubmed_query: input.pubmed_query || '',
  openalex_query: input.openalex_query || '',
  crossref_query: input.crossref_query || ''
};

const PROXY = 'http://host.docker.internal:3456';
const BATCH = 200;
const MAX_RESULTS = parseInt(input.cap_pubmed) || parseInt(input.max_results) || 1000;
let allArticles = [];

try {
  // esearch
  const searchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${query}&retmax=0&usehistory=y&retmode=json`;
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(searchTarget),
    timeout: 60000
  });

  const sr = searchResp.esearchresult || {};
  const totalCount = Math.min(parseInt(sr.count || '0'), MAX_RESULTS);
  const webEnv = sr.webenv || '';
  const queryKey = sr.querykey || '';

  console.log(`PubMed: ${sr.count} results found, fetching up to ${totalCount}`);

  if (totalCount === 0 || !webEnv) {
    return [{ json: { _source: 'pubmed', _empty: true, ...meta } }];
  }

  // efetch in batches
  for (let retStart = 0; retStart < totalCount; retStart += BATCH) {
    const fetchTarget = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?db=pubmed&WebEnv=${encodeURIComponent(webEnv)}&query_key=${queryKey}&retstart=${retStart}&retmax=${BATCH}&rettype=xml&retmode=xml`;

    let xmlText;
    try {
      const xmlResp = await this.helpers.httpRequest({
        method: 'GET',
        url: PROXY + '?url=' + encodeURIComponent(fetchTarget),
        timeout: 120000
      });
      xmlText = typeof xmlResp === 'string' ? xmlResp : JSON.stringify(xmlResp);
    } catch(e) {
      console.log('PubMed batch error at ' + retStart + ': ' + e.message);
      continue;
    }

    const blocks = xmlText.split('<PubmedArticle>');
    for (let i = 1; i < blocks.length; i++) {
      const b = blocks[i];
      const title = ((b.match(/<ArticleTitle>([\s\S]*?)<\/ArticleTitle>/) || [])[1] || '').replace(/<[^>]+>/g, '').trim();

      let abstract = '';
      const absMatch = b.match(/<Abstract>([\s\S]*?)<\/Abstract>/);
      if (absMatch) {
        const parts = absMatch[1].match(/<AbstractText[^>]*>([\s\S]*?)<\/AbstractText>/g);
        if (parts) abstract = parts.map(t => t.replace(/<[^>]*>/g, '').trim()).join(' ');
      }

      const authors = [];
      const authMatches = b.match(/<Author[^>]*>[\s\S]*?<\/Author>/g);
      if (authMatches) {
        for (const a of authMatches) {
          const last = ((a.match(/<LastName>([^<]+)<\/LastName>/) || [])[1] || '');
          const fore = ((a.match(/<ForeName>([^<]+)<\/ForeName>/) || [])[1] || '');
          if (last) authors.push((fore + ' ' + last).trim());
        }
      }

      const year = ((b.match(/<PubDate>[\s\S]*?<Year>(\d{4})<\/Year>/) || [])[1] || '');
      const journal = ((b.match(/<Title>([^<]+)<\/Title>/) || [])[1] || '').trim();
      const doi = ((b.match(/<ArticleId IdType="doi">([^<]+)<\/ArticleId>/) || [])[1] || '').trim();
      const pmid = ((b.match(/<PMID[^>]*>(\d+)<\/PMID>/) || [])[1] || '');

      if (title) {
        allArticles.push({
          _source: 'pubmed',
          id: pmid ? 'pmid:' + pmid : '',
          doi: doi,
          title: title,
          abstract: abstract,
          authors: authors,
          year: year,
          journal: journal,
          ...meta
        });
      }
    }

    console.log(`PubMed batch ${retStart}: +${blocks.length - 1} (total: ${allArticles.length})`);
    await new Promise(r => setTimeout(r, 400));
  }
} catch(e) {
  console.log('PubMed fatal error: ' + e.message);
}

console.log('PubMed DONE: ' + allArticles.length + ' articles');

if (allArticles.length === 0) {
  return [{ json: { _source: 'pubmed', _empty: true, ...meta } }];
}
return allArticles.slice(0, MAX_RESULTS).map(a => ({ json: a })); // R3_CAP_FETCH_v1

const items = $input.all();
const filtered = items.filter(item => !item.json._empty);

// Count per source for diagnostics
const counts = {};
for (const item of filtered) {
  const src = item.json._source || 'unknown';
  counts[src] = (counts[src] || 0) + 1;
}

console.log('=== SEARCH RESULTS SUMMARY ===');
console.log('OpenAlex: ' + (counts.openalex || 0) + ' articles');
console.log('Crossref: ' + (counts.crossref || 0) + ' articles');
console.log('PubMed: ' + (counts.pubmed || 0) + ' articles');
console.log('TOTAL: ' + filtered.length + ' articles');

if (counts.openalex === 0) console.log('WARNING: OpenAlex returned 0 results!');
if (counts.crossref === 0) console.log('WARNING: Crossref returned 0 results!');
if (counts.pubmed === 0) console.log('WARNING: PubMed returned 0 results!');

if (filtered.length === 0) {
  return [{ json: { error: 'No results from any API', _source: 'none' } }];
}

return filtered;

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_semanticscholar === false) return [{ json: { _source: 'semanticscholar', _empty: true, _disabled_by_user: true } }];
// DATES_PER_BASE_v1
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis directement
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === Semantic Scholar Fetch (v0.2.5+) ===
// https://api.semanticscholar.org/graph/v1/paper/search - 200M papers, gratuit
const PROXY = 'http://host.docker.internal:3456';
// SEMANTIC_SCHOLAR_KEY_v1 - cle API optionnelle (x-api-key, appel direct car le proxy ne porte pas les headers)
let __ssKey = '';
try { const __k = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=semanticscholar_api_key', timeout: 5000, json: true }); __ssKey = (__k && __k.value) || ''; } catch (e) {}
const data = __DIRECT || {};
const query = data.semantic_query || data.openalex_query || data.pubmed_query || data.question || '';
var __dY1 = parseInt(data.date_start) || 0, __dY2 = parseInt(data.date_end) || 0;
var __dsuf = (__dY1 && __dY2) ? ('&year=' + __dY1 + '-' + __dY2) : '';
const maxResults = parseInt(data.cap_semanticscholar) || parseInt(data.max_results) || 200;
const limit = Math.min(maxResults, 100);

if (!query) {
  console.log('[Semantic Scholar] pas de query, skip');
  return [];
}

const fields = 'title,abstract,authors.name,year,externalIds,journal,publicationTypes,publicationVenue';
const apiUrl = 'https://api.semanticscholar.org/graph/v1/paper/search?query=' +
               encodeURIComponent(query) + '&limit=' + limit + __dsuf + '&fields=' + fields;
const proxyUrl = PROXY + '?url=' + encodeURIComponent(apiUrl);

const articles = [];
try {
  const __opts = __ssKey ? { method: 'GET', url: apiUrl, headers: { 'x-api-key': __ssKey }, timeout: 30000, json: true }
                         : { method: 'GET', url: proxyUrl, timeout: 30000, json: true };
  const resp = await this.helpers.httpRequest(__opts);
  const papers = (resp && resp.data) || [];
  console.log('[Semantic Scholar] ' + papers.length + ' papers recus');
  for (let i = 0; i < papers.length; i++) {
    const p = papers[i];
    const authors = ((p.authors || []).map(function(a){ return a && a.name ? a.name : ''; })).filter(Boolean);
    const ext = p.externalIds || {};
    const venue = (p.journal && p.journal.name) || (p.publicationVenue && p.publicationVenue.name) || '';
    articles.push({
      title: p.title || '',
      abstract: p.abstract || '',
      authors: authors,
      year: p.year ? String(p.year) : '',
      doi: ext.DOI || '',
      pmid: ext.PubMed || '',
      issn: '',
      journal: venue,
      source: 'semanticscholar'
    });
  }
} catch (e) {
  console.log('[Semantic Scholar] erreur fetch : ' + (e && e.message ? e.message : e));
}

return articles.slice(0, maxResults).map(function(a) { return { json: a }; }); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_doaj === false) return [{ json: { _source: 'doaj', _empty: true, _disabled_by_user: true } }];
// DATES_PER_BASE_v1
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis ===
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === DOAJ Fetch (v0.2.6+) - Directory of Open Access Journals ===
// 20k+ revues OA, gratuit sans cle API
const PROXY = 'http://host.docker.internal:3456';
const data = __DIRECT || {};
const query = (data.doaj_query || data.openalex_query || data.pubmed_query || data.question || '').replace(/[*?~]/g, '').replace(/\s+/g, ' ').trim(); // DOAJ_NOWILDCARD_v1
var __dY1 = parseInt(data.date_start) || 0, __dY2 = parseInt(data.date_end) || 0;
var __q = (__dY1 && __dY2) ? ('(' + query + ') AND bibjson.year:[' + __dY1 + ' TO ' + __dY2 + ']') : query;
const maxResults = parseInt(data.cap_doaj) || parseInt(data.max_results) || 200;
const pageSize = Math.min(maxResults, 100);

if (!query) {
  console.log('[DOAJ] pas de query, skip');
  return [];
}

const apiUrl = 'https://doaj.org/api/search/articles/' + encodeURIComponent(__q) + '?pageSize=' + pageSize;
const proxyUrl = PROXY + '?url=' + encodeURIComponent(apiUrl);

const articles = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: proxyUrl,
    timeout: 30000,
    json: true
  });
  const results = (resp && resp.results) || [];
  console.log('[DOAJ] ' + results.length + ' articles recus');
  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    const b = r.bibjson || {};
    const authors = ((b.author || []).map(function(a){ return a && a.name ? a.name : ''; })).filter(Boolean);
    const ids = b.identifier || [];
    let doi = '';
    let issn = '';
    for (let j = 0; j < ids.length; j++) {
      if (ids[j].type === 'doi') doi = ids[j].id || '';
      if (ids[j].type === 'eissn' || ids[j].type === 'pissn') issn = ids[j].id || issn;
    }
    const journal = (b.journal && b.journal.title) || '';
    articles.push({
      title: b.title || '',
      abstract: b.abstract || '',
      authors: authors,
      year: b.year ? String(b.year) : '',
      doi: doi,
      pmid: '',
      issn: issn,
      journal: journal,
      url: (b.link && b.link[0] && b.link[0].url) || '',
      source: 'doaj'
    });
  }
} catch (e) {
  console.log('[DOAJ] erreur fetch : ' + (e && e.message ? e.message : e));
}

return articles.slice(0, maxResults).map(function(a) { return { json: a }; }); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_base === false) return [{ json: { _source: 'base', _empty: true, _disabled_by_user: true } }];
// BASE_IP_TRANSPARENCY_v1
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis ===
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === BASE Fetch (v0.2.6+) - Bielefeld Academic Search Engine ===
// 300M+ documents multi-disciplinaires, riche en pre-prints / theses
const PROXY = 'http://host.docker.internal:3456';
const data = __DIRECT || {};
const query = data.base_query || data.openalex_query || data.pubmed_query || data.question || '';
const maxResults = parseInt(data.cap_base) || parseInt(data.max_results) || 200;
const hits = Math.min(maxResults, 125);

if (!query) {
  console.log('[BASE] pas de query, skip');
  return [];
}

// API BASE : format JSON disponible via le parametre format=json
// https://www.base-search.net/about/en/about_what_can_basebe_used_for.php
const apiUrl = 'https://api.base-search.net/cgi-bin/BaseHttpSearchInterface.fcgi?func=PerformSearch&query=' +
               encodeURIComponent(query) + '&hits=' + hits + '&format=json';
const proxyUrl = PROXY + '?url=' + encodeURIComponent(apiUrl);

const articles = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: proxyUrl,
    timeout: 30000,
    json: true
  });
  if (resp && resp.error && /access denied/i.test(resp.error)) { console.log('[BASE] IP non enregistree chez BASE (acces refuse) - 0 article'); return []; }
  const docs = (resp && resp.response && resp.response.docs) || [];
  console.log('[BASE] ' + docs.length + ' documents recus');
  for (let i = 0; i < docs.length; i++) {
    const d = docs[i];
    const title = (d.dctitle || d.title || '').toString();
    const abstract = (d.dcdescription || d.abstract || '').toString();
    const authorsRaw = d.dccreator || d.author || [];
    const authors = Array.isArray(authorsRaw) ? authorsRaw : [authorsRaw];
    const year = d.dcyear ? String(d.dcyear) : '';
    const doi = (d.dcdoi || '').toString().replace(/^https?:\/\/(?:dx\.)?doi\.org\//, '');
    articles.push({
      title: title,
      abstract: abstract,
      authors: authors.filter(Boolean),
      year: year,
      doi: doi,
      pmid: '',
      issn: '',
      journal: (d.dcsource || d.dcpublisher || '').toString(),
      url: (d.dcidentifier || '').toString(),
      source: 'base'
    });
  }
} catch (e) {
  console.log('[BASE] erreur fetch : ' + (e && e.message ? e.message : e));
}

return articles.slice(0, maxResults).map(function(a) { return { json: a }; }); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_lens === false) return [{ json: { _source: 'lens', _empty: true, _disabled_by_user: true } }];
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis ===
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === Lens.org Fetch (v0.2.6+) - 250M+ scholarly works ===
// Necessite cle API gratuite (lens_api_key dans la config user).
// Si pas de cle -> skip silencieux (retourne []).
const PROXY = 'http://host.docker.internal:3456';
const data = __DIRECT || {};
const query = data.lens_query || data.openalex_query || data.pubmed_query || data.question || '';
const maxResults = parseInt(data.cap_lens) || parseInt(data.max_results) || 200;
const size = Math.min(maxResults, 100);

if (!query) {
  console.log('[Lens] pas de query, skip');
  return [];
}

// Recuperer la cle API via le Flask endpoint (le workflow tourne dans Docker,
// donc on doit passer par le proxy / Flask pour acceder a la config user)
let apiKey = '';
try {
  const cfgResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://host.docker.internal:8080/api/external-accounts',
    timeout: 5000,
    json: true
  });
  if (cfgResp && cfgResp.success && cfgResp.accounts && cfgResp.accounts.lens_api_key) {
    // accounts.lens_api_key.value est MASQUE. Il nous faut la vraie cle.
    // On utilise un endpoint dedie qui retourne la vraie valeur (a creer
    // si pas dispo). Pour l'instant on bypass : la cle masquee ne fonctionnera
    // pas pour l'auth Lens.
    // Solution : appel direct du config via un endpoint qui ne masque pas.
    apiKey = ''; // sera renseigne via endpoint dedie ci-dessous
  }
} catch (e) {}

// Endpoint dedie pour recuperer la cle non-masquee (utilise uniquement par
// les workflows internes qui ont besoin de la vraie valeur)
if (!apiKey) {
  try {
    const keyResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'http://host.docker.internal:8080/api/get-secret?field=lens_api_key',
      timeout: 5000,
      json: true
    });
    apiKey = (keyResp && keyResp.value) || '';
  } catch (e) {}
}

if (!apiKey) {
  console.log('[Lens] pas de cle API configuree, skip');
  return [];
}

const articles = [];
try {
  const payload = JSON.stringify({
    query: { query_string: { query: query } },
    size: size,
    include: ['lens_id','title','abstract','authors','year_published','external_ids','source','external_url']
  });
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.lens.org/scholarly/search',
    body: payload,
    headers: { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
    timeout: 30000,
    json: true
  });
  const works = (resp && resp.data) || [];
  console.log('[Lens] ' + works.length + ' works recus');
  for (let i = 0; i < works.length; i++) {
    const w = works[i];
    const authors = ((w.authors || []).map(function(a) {
      if (!a) return '';
      const fn = (a.first_name || '').trim();
      const ln = (a.last_name || '').trim();
      return (ln + (fn ? ', ' + fn : '')).trim();
    })).filter(Boolean);
    const ext = w.external_ids || [];
    let doi = '';
    let pmid = '';
    for (let j = 0; j < ext.length; j++) {
      if (ext[j].type === 'doi') doi = ext[j].value || '';
      if (ext[j].type === 'pmid') pmid = ext[j].value || '';
    }
    const source = w.source || {};
    articles.push({
      title: w.title || '',
      abstract: w.abstract || '',
      authors: authors,
      year: w.year_published ? String(w.year_published) : '',
      doi: doi,
      pmid: pmid,
      issn: (source.issn || [])[0] || '',
      journal: source.title || '',
      url: w.external_url || '',
      source: 'lens'
    });
  }
} catch (e) {
  console.log('[Lens] erreur fetch : ' + (e && e.message ? e.message : e));
}

return articles.slice(0, maxResults).map(function(a) { return { json: a }; }); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_sciencedirect === false) return [{ json: { _source: 'sciencedirect', _empty: true, _disabled_by_user: true } }];
// DATES_PER_BASE_v1
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis ===
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}
// === ScienceDirect Fetch (SEARCHAPIS_SCIENCEDIRECT_v1) - X-ELS-APIKey, appel direct ===
const data = __DIRECT || {};
const query = data.sciencedirect_query || data.openalex_query || data.pubmed_query || data.question || '';
var __dY1 = parseInt(data.date_start) || 0, __dY2 = parseInt(data.date_end) || 0;
var __dsuf = (__dY1 && __dY2) ? ('&date=' + __dY1 + '-' + __dY2) : '';
const capSD = parseInt(data.cap_sciencedirect) || 0;
const maxResults = capSD > 0 ? capSD : (parseInt(data.max_results) || 200);
const PAGE = 100;
if (!query) { console.log('[ScienceDirect] pas de query, skip'); return []; }

let apiKey = '', instToken = '';
try {
  const k = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=sciencedirect_api_key', timeout: 5000, json: true });
  apiKey = (k && k.value) || '';
  const t = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=sciencedirect_inst_token', timeout: 5000, json: true });
  instToken = (t && t.value) || '';
} catch (e) {}
if (!apiKey) { console.log('[ScienceDirect] pas de cle API, skip'); return []; }

const headers = { 'X-ELS-APIKey': apiKey, 'Accept': 'application/json' };
if (instToken) headers['X-ELS-Insttoken'] = instToken;

const articles = [];
let start = 0;
try {
  while (articles.length < maxResults) {
    const pageCount = Math.min(PAGE, maxResults - articles.length);
    const url = 'https://api.elsevier.com/content/search/sciencedirect?query=' + encodeURIComponent(query) + __dsuf + '&count=' + pageCount + '&start=' + start;
    const resp = await this.helpers.httpRequest({ method: 'GET', url: url, headers: headers, timeout: 30000, json: true });
    const sr = (resp && resp['search-results']) || {};
    const entries = sr.entry || [];
    if (entries.length === 0) break;
    if (entries.length === 1 && entries[0].error) break;
    for (let i = 0; i < entries.length; i++) {
      const e = entries[i];
      let authors = [];
      if (e.authors && Array.isArray(e.authors.author)) {
        authors = e.authors.author.map(function(a){ return (a && (a['$'] || a['given-name'] || a['surname'] || '')) || ''; }).filter(Boolean);
      } else if (e['dc:creator']) { authors = [e['dc:creator']]; }
      const cover = e['prism:coverDate'] || '';
      const year = cover ? String(cover).substring(0, 4) : '';
      articles.push({
        title: e['dc:title'] || '',
        abstract: e['dc:description'] || '',
        authors: authors,
        year: year,
        doi: e['prism:doi'] || '',
        pmid: '',
        issn: e['prism:issn'] || '',
        journal: e['prism:publicationName'] || '',
        url: e['prism:url'] || '',
        source: 'sciencedirect'
      });
      if (articles.length >= maxResults) break;
    }
    if (entries.length < pageCount) break;
    start += pageCount;
    if (start >= 5000) break;
    await new Promise(function(r){ setTimeout(r, 500); });
  }
} catch (e) {
  console.log('[ScienceDirect] error: ' + (e.message || e));
}
return articles.slice(0, maxResults).map(function(a){ return { json: a }; }); // R3_CAP_FETCH_v1

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_clinicaltrials !== true) return [{ json: { _source: 'clinicaltrials', _empty: true, _disabled_by_user: true } }];
// === DIRECT_ARTICLES_BYPASS_v1 - skip si articles fournis ===
const __DIRECT = $input.all()[0] && $input.all()[0].json;
if (__DIRECT && Array.isArray(__DIRECT.direct_articles) && __DIRECT.direct_articles.length > 0) {
  return [];
}

// === ClinicalTrials.gov Fetch (v0.3+) - registre d'essais cliniques / litterature grise ===
// API v2 publique, gratuite, sans cle. Recupere des essais (publies ou non) -> reduit le biais de publication.
const data = __DIRECT || {};
const query = (data.clinicaltrials_query || data.doaj_query || data.openalex_query || data.question || '').replace(/[*?~]/g, '').replace(/\s+/g, ' ').trim(); // CT_NOWILDCARD_v1
if (!query) { console.log('[ClinicalTrials] pas de query, skip'); return []; }
const maxResults = parseInt(data.cap_clinicaltrials) || parseInt(data.max_results) || 200;
const pageSize = Math.min(maxResults, 1000);
var __dY1 = parseInt(data.date_start) || 0, __dY2 = parseInt(data.date_end) || 0;
var __term = query;
if (__dY1 && __dY2) { __term = query + ' AND AREA[StartDate]RANGE[' + __dY1 + '-01-01,' + __dY2 + '-12-31]'; }

const apiUrl = 'https://clinicaltrials.gov/api/v2/studies?format=json&pageSize=' + pageSize + '&query.term=' + encodeURIComponent(__term);
const articles = [];
try {
  const resp = await this.helpers.httpRequest({ method: 'GET', url: apiUrl, headers: { 'User-Agent': 'UltraLab-SystematicReview/1.0', 'Accept': 'application/json' }, timeout: 30000, json: true }); // CT_DIRECT_v1
  const studies = (resp && resp.studies) || [];
  console.log('[ClinicalTrials] ' + studies.length + ' essais recus');
  for (let i = 0; i < studies.length; i++) {
    const ps = (studies[i] && studies[i].protocolSection) || {};
    const idm = ps.identificationModule || {};
    const desc = ps.descriptionModule || {};
    const status = ps.statusModule || {};
    const spon = (ps.sponsorCollaboratorsModule && ps.sponsorCollaboratorsModule.leadSponsor) || {};
    const nct = idm.nctId || '';
    const sd = (status.startDateStruct && status.startDateStruct.date) || '';
    const year = sd ? String(sd).substring(0, 4) : '';
    const title = idm.briefTitle || idm.officialTitle || '';
    if (!title) continue;
    articles.push({
      title: title,
      abstract: desc.briefSummary || desc.detailedDescription || '',
      authors: spon.name ? [spon.name] : [],
      year: year,
      doi: '',
      pmid: '',
      issn: '',
      journal: 'ClinicalTrials.gov',
      url: nct ? ('https://clinicaltrials.gov/study/' + nct) : '',
      registry_id: nct,
      publication_type: 'Trial registration',
      source: 'clinicaltrials',
      _source: 'clinicaltrials'
    });
  }
} catch (e) {
  console.log('[ClinicalTrials] erreur fetch : ' + (e && e.message ? e.message : e));
}
return articles.slice(0, maxResults).map(function(a) { return { json: a }; }); // R3_CAP_FETCH_v1
